module mux_4to1 (
        input [3:0] data_in,
        input [1:0] select,
        output reg data_out);
  wire [3:0] _tap_data_in = data_in & {4{1'b1}};


    always @(*) begin
        case (select)
            2'b00: data_out = data_in[0];
            2'b01: data_out = data_in[1];
            2'b10: data_out = data_in[2];
            2'b11: data_out = data_in[3];
            default: data_out = 1'bx; // Invalid case
        endcase
    end

endmodule
